import React, { useEffect, useState } from 'react';
import { supabase } from '../services/supabaseClient';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, Cell } from 'recharts';

const Dashboard = () => {
  const [dados, setDados] = useState([]);

  useEffect(() => {
    async function carregarDados() {
      const { data } = await supabase.from('compras').select('valor_total, loja');
      if (data) {
        // Agrupa por loja
        const agrupado = data.reduce((acc, item) => {
          const nomeLoja = item.loja || 'Não informada';
          acc[nomeLoja] = (acc[nomeLoja] || 0) + parseFloat(item.valor_total);
          return acc;
        }, {});

        const formatado = Object.keys(agrupado).map(loja => ({
          loja: loja,
          total: agrupado[loja]
        }));
        
        setDados(formatado.sort((a, b) => b.total - a.total)); // Ordena do maior para o menor
      }
    }
    carregarDados();
  }, []);

  return (
    <div className="fade-in">
      <h2 style={{ marginBottom: '25px' }}>Análise de Gastos por Loja</h2>
      
      <div className="card" style={{ height: '450px' }}>
        <ResponsiveContainer width="100%" height="100%">
          <BarChart data={dados} margin={{ top: 20, right: 30, left: 20, bottom: 60 }}>
            <CartesianGrid strokeDasharray="3 3" vertical={false} />
            <XAxis dataKey="loja" angle={-45} textAnchor="end" interval={0} height={80} />
            <YAxis />
            <Tooltip 
              formatter={(value) => `R$ ${value.toLocaleString('pt-BR')}`}
              contentStyle={{ borderRadius: '10px', border: 'none', boxShadow: '0 4px 12px rgba(0,0,0,0.1)' }}
            />
            <Bar dataKey="total" fill="var(--primary)" radius={[4, 4, 0, 0]}>
              {dados.map((entry, index) => (
                <Cell key={`cell-${index}`} fill={index % 2 === 0 ? '#6366f1' : '#818cf8'} />
              ))}
            </Bar>
          </BarChart>
        </ResponsiveContainer>
      </div>
    </div>
  );
};

export default Dashboard;
